package cookies_test

import (
	"net/http"
	"testing"

	"github.com/flightctl/flightctl/internal/auth/common/cookies"
	"github.com/stretchr/testify/require"
)

func TestCookieParsing(t *testing.T) {
	t.Run("no header", func(t *testing.T) {
		r := http.Request{Header: make(http.Header)}

		_, err := cookies.ParseSessionCookie(&r)
		require.Error(t, err)
	})

	t.Run("valid cookie", func(t *testing.T) {
		r := http.Request{Header: make(http.Header)}

		// This is based on values from existing UI requests.
		r.Header.Add("Cookie", `auth=hfQZcZ9L3Miaw7krVKjueHPDxncAgqrmy9aoTRwxvZvVmPeZAUZcSscqd_1DxcL2HdqeNlw0F0eXe6wRrR0Yboim1BWX5AGifAQxQlc3_ruCPYA1gJ0XCtIxDIqQBWSRuxniccfz31HS5pH-XN-0Ag5MX1xCxgxlF5ePATKlUfiKixfJFvpkHuygCE0Ysq_OzDULc8R1B8QXReYAxK4pv9Mbavdmo7TTDEZ4XmlGBVEQWCPvRQ7ghwYLYPi6rX8qRDTAzbmosY28uRPEhL1ASo2S-JMzxAhu5Z45fU-uXikbV08aTcJy8ThkcMQdHbGo7iR_EH2olLo32z16Uo43nLVpkuEFNRV3AmEWQUaStgp2oWI8Z4FN6AIFz0ssBaOjtZjm6wXCCvUPCKBiJIgO_jnd-vG2mMavrYvwklyIUSoiQ4TAYwmpgTujeHs6ZccHyeAKHKidagkyjVeDzuryie_P8U_8Shb-27pqEmFMohc6jy8ZwH8hDUWWDOal7p43H3nLYk-oMwEHe6bzuCO-7DEL; flightctl-`)

		token, err := cookies.ParseSessionCookie(&r)
		require.NoError(t, err)
		require.Equal(t, token.Token, `eyJhbGciOiJFUzI1NiIsImtpZCI6IjBkYmFjZDFmOTc0MzljNTYiLCJ0eXAiOiJKV1QifQ..EChJzBbexvfo6LnP0YNd4e6ScqGUlJedfb-8McR1Og-pVu01q32CJH1BmUwDAIjNrjuATDDC0vcGwBNYcSgyWg`)
	})
}

func TestCookieEncoding(t *testing.T) {
	token := cookies.TokenData{
		Token:        "eyJhbGciOiJFUzI1NiIsImtpZCI6IjBkYmFjZDFmOTc0MzljNTYiLCJ0eXAiOiJKV1QifQ..EChJzBbexvfo6LnP0YNd4e6ScqGUlJedfb-8McR1Og-pVu01q32CJH1BmUwDAIjNrjuATDDC0vcGwBNYcSgyWg",
		RefreshToken: "eyJhbGciOiJFUzI1NiIsImtpZCI6IjBkYmFjZDFmOTc0MzljNTYiLCJ0eXAiOiJKV1QifQ..f-eLPbuBUhpQ62ZIxjHsQJT_f095LDE4xXPtK2nitGvxziFCiRbjyZkCdjh__QUbtClvM834MU5wBCV_X-kjCQ",
		Provider:     "oidc",
	}
	encoded, err := cookies.EncodeTokenForCookie(token)
	require.NoError(t, err)
	require.Equal(t, encoded, ``)
}
